"use client";

import { useEffect, useState, type FormEvent } from "react";

const PORTRAIT = "data:image/png;base64,";
const CAP = "data:image/png;base64,";
const W3F_KEY: string = "ba71783e-c8fb-4ef7-9ac4-32ec1ca0a7a5"; // Web3Forms access key (public by design)
const FALLBACK_EMAIL = "cohen72@gmail.com";

/* ---------- icons ---------- */
const S = { fill: "none", stroke: "currentColor", strokeWidth: 2, strokeLinecap: "round" as const, strokeLinejoin: "round" as const };
const IconSun = () => (<svg viewBox="0 0 24 24" {...S}><circle cx="12" cy="12" r="4" /><path d="M12 2v2M12 20v2M4.9 4.9l1.4 1.4M17.7 17.7l1.4 1.4M2 12h2M20 12h2M4.9 19.1l1.4-1.4M17.7 6.3l1.4-1.4" /></svg>);
const IconMoon = () => (<svg viewBox="0 0 24 24" {...S}><path d="M21 12.8A9 9 0 1 1 11.2 3a7 7 0 0 0 9.8 9.8z" /></svg>);
const IconScreen = () => (<svg viewBox="0 0 24 24" {...S}><rect x="2" y="3" width="20" height="14" rx="2" /><path d="M8 21h8M12 17v4" /></svg>);
const IconGear = () => (<svg viewBox="0 0 24 24" {...S}><path d="M12 2v4M12 18v4M2 12h4M18 12h4M5 5l3 3M16 16l3 3M19 5l-3 3M8 16l-3 3" /><circle cx="12" cy="12" r="3" /></svg>);
const IconPlug = () => (<svg viewBox="0 0 24 24" {...S}><path d="M8 7L3 12l5 5M16 7l5 5-5 5M14 4l-4 16" /></svg>);
const IconPhone = () => (<svg viewBox="0 0 24 24" {...S}><path d="M22 16.9v3a2 2 0 0 1-2.2 2 19.8 19.8 0 0 1-8.6-3.1 19.5 19.5 0 0 1-6-6 19.8 19.8 0 0 1-3.1-8.7A2 2 0 0 1 4.1 2h3a2 2 0 0 1 2 1.7c.1 1 .4 2 .7 2.9a2 2 0 0 1-.5 2.1L8.1 9.9a16 16 0 0 0 6 6l1.2-1.2a2 2 0 0 1 2.1-.5c.9.3 1.9.6 2.9.7a2 2 0 0 1 1.7 2z" /></svg>);
const IconDoc = () => (<svg viewBox="0 0 24 24" {...S}><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z" /><path d="M14 2v6h6M9 13h6M9 17h6" /></svg>);
const IconCheckBig = () => (<svg viewBox="0 0 24 24" {...S}><path d="M20 6L9 17l-5-5" /></svg>);
const Check = () => (<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={3} strokeLinecap="round"><path d="M5 12l4 4L19 6" /></svg>);

/* ---------- data ---------- */
const SERVICES = [
  { n: "01", Icon: IconScreen, title: "Websites", body: "A small, considered site that loads quickly, reads well on a phone, and is easy to update yourself — your site, CRM, bookings and follow-ups in one tidy place.", bullets: ["3–6 page builds", "Mobile-first", "All-in-one back end", "Owned by you"], price: "$1,800" },
  { n: "02", Icon: IconGear, title: "Automations", body: "The quiet plumbing that follows up with leads, sends reminders, and stops things falling through the cracks. Set up once, refined together, then it just runs.", bullets: ["Email + SMS sequences", "Lead routing", "No-show recovery", "Internal hand-offs"], price: "$600" },
  { n: "03", Icon: IconPlug, title: "Integrations", body: "Bookings, payments, calendars and CRMs — wired together so your tools talk to each other instead of through you. The usual suspects, neatly connected.", bullets: ["Booking systems", "Payments + invoicing", "CRM + calendar sync", "Custom webhooks"], price: "$400" },
];

const PROJECTS = [
  { url: "https://www.malcohen.com", host: "malcohen.com", title: "Malcolm Cohen Art", type: "Artist portfolio · Website", desc: "A gallery for a painter's landscapes, portraits, and colorful mixed-media work.", shot: "data:image/jpeg;base64," },
  { url: "https://www.sixthings.today", host: "sixthings.today", title: "Sixthings", type: "App landing page · Website", desc: "Marketing site for a focus app built on the Ivy Lee method — six tasks, one priority, daily streaks.", shot: "data:image/jpeg;base64," },
  { url: "http://dumbassphotoshop.com/", host: "dumbassphotoshop.com", title: "Dumbass Photoshop", type: "Service brand · Website", desc: "A personality-first site with tiered licensing for a meme-edit studio.", shot: "data:image/jpeg;base64," },
  { url: "https://themothersmarch.vercel.app/", host: "themothersmarch.app", title: "The Mother's March", type: "Nonprofit · Donations", desc: "A donation site for volunteers bringing hot Shabbat meals to soldiers up north.", shot: "data:image/jpeg;base64," },
];

const PROCESS = [
  { Icon: IconPhone, title: "A short call", body: "A quick call to understand your goals and the scope of the work." },
  { Icon: IconDoc, title: "A written plan", body: "A clear, fixed-price plan: scope, timeline, and cost — on one page." },
  { Icon: IconCheckBig, title: "Build & hand-off", body: "We build, you review, we launch — then hand everything over to you." },
];

const FAQS = [
  { q: "What platform do you build on?", a: "We work with a small set of platforms we trust. After the first call we'll recommend the right one for your situation — it depends on what you need now and where you might grow. The point is the right tools, not the most." },
  { q: "What does a website cost?", a: "Most small business sites land between $1,800 and $3,500 depending on pages and complexity. You'll get a flat quote in writing before any work starts. No hourly creep." },
  { q: "Do you offer ongoing support?", a: "Yes — when it makes sense. After launch you get 30 days of free adjustments. After that, support is available hourly or on a small monthly care plan." },
  { q: "Can you take over a site I already have?", a: "Often, yes. If your current setup is reasonable and the goal is real improvement, we can build on it. If a rebuild would serve you better, we'll say so." },
  { q: "Not sure what you need?", a: "That's what the first call is for. Bring your half-formed thoughts and we'll sort them out together." },
];

const HELP_OPTS = ["A new website", "Bookings setup", "Automations", "Integrations", "Not sure yet"];
const BUDGET_OPTS = ["< $2k", "$2k – 5k", "$5k – 10k", "$10k+", "Not sure"];

export default function Home() {
  const [scrolled, setScrolled] = useState(false);
  const [theme, setTheme] = useState<"dark" | "light">("dark");
  const [openFaq, setOpenFaq] = useState<number | null>(0);
  const [help, setHelp] = useState<string[]>(["A new website"]);
  const [budget, setBudget] = useState<string | null>(null);
  const [sent, setSent] = useState(false);

  useEffect(() => {
    const cur = document.documentElement.getAttribute("data-theme");
    if (cur === "light" || cur === "dark") setTheme(cur);
  }, []);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 8);
    onScroll();
    window.addEventListener("scroll", onScroll, { passive: true });
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  useEffect(() => {
    const els = Array.from(document.querySelectorAll<HTMLElement>(".rv"));
    if (!("IntersectionObserver" in window)) {
      els.forEach((e) => e.classList.add("in"));
      return;
    }
    const io = new IntersectionObserver(
      (entries) => entries.forEach((e) => { if (e.isIntersecting) { e.target.classList.add("in"); io.unobserve(e.target); } }),
      { threshold: 0.12, rootMargin: "0px 0px -8% 0px" }
    );
    els.forEach((e) => io.observe(e));
    const failsafe = setTimeout(() => els.forEach((e) => e.classList.add("in")), 1600);
    return () => { clearTimeout(failsafe); io.disconnect(); };
  }, []);

  const toggleTheme = () => {
    const next = theme === "dark" ? "light" : "dark";
    setTheme(next);
    document.documentElement.setAttribute("data-theme", next);
    try { localStorage.setItem("yoco-theme", next); } catch (e) { /* ignore */ }
  };

  const toggleHelp = (v: string) =>
    setHelp((s) => (s.includes(v) ? s.filter((x) => x !== v) : [...s, v]));

  async function handleSubmit(e: FormEvent<HTMLFormElement>) {
    e.preventDefault();
    const fd = new FormData(e.currentTarget);
    const get = (k: string) => ((fd.get(k) as string) || "").trim();
    const name = get("name"), email = get("email"), business = get("business"), timeline = get("timeline"), message = get("message");
    const fields = { name, email, business, timeline, help: help.join(", "), budget: budget || "", message };
    if (W3F_KEY && W3F_KEY.length > 10) {
      try {
        const res = await fetch("https://api.web3forms.com/submit", {
          method: "POST",
          headers: { "Content-Type": "application/json", Accept: "application/json" },
          body: JSON.stringify({ access_key: W3F_KEY, from_name: "yoco.works", subject: `New project inquiry${name ? " — " + name : ""}`, ...fields }),
        });
        if (res.ok) { setSent(true); return; }
      } catch (err) { /* fall through to mailto */ }
    }
    const body = `Name: ${name}\nEmail: ${email}\nBusiness: ${business}\nTimeline: ${timeline}\nHelp: ${fields.help}\nBudget: ${fields.budget}\n\n${message}`;
    window.location.href = `mailto:${FALLBACK_EMAIL}?subject=${encodeURIComponent("New project inquiry" + (name ? " — " + name : ""))}&body=${encodeURIComponent(body)}`;
    setSent(true);
  }

  return (
    <>
      <header className={scrolled ? "scrolled" : ""} id="top">
        <div className="wrap nav">
          <a className="brand" href="#top"><span className="yoco">yoco</span>{/* eslint-disable-next-line @next/next/no-img-element */}<img className="cap" src={CAP} alt="" /><span className="works">works</span></a>
          <nav className="navlinks">
            <a href="#services">Services</a>
            <a href="#work">Work</a>
            <a href="#process">Process</a>
            <a href="#about">About</a>
            <a href="#faq">FAQ</a>
          </nav>
          <div className="nav-right">
            <button className="toggle" onClick={toggleTheme} aria-label="Toggle light and dark mode">
              {theme === "dark" ? <IconSun /> : <IconMoon />}
            </button>
            <a className="btn btn-primary" href="#contact">Get in touch <span className="arr">→</span></a>
          </div>
        </div>
      </header>

      <main>
        {/* HERO */}
        <section className="hero">
          <div className="hero-bg" aria-hidden="true" />
          <div className="wrap">
            <h1 className="hero-mark"><span className="yoco">yoco</span>{/* eslint-disable-next-line @next/next/no-img-element */}<img className="cap" src={CAP} alt="" /><span className="works">works</span></h1>
            <p className="hero-sub">We build well-made websites — and the quiet workflows behind them.</p>
            <div className="hero-cta">
              <a className="btn btn-primary" href="#contact">Start a project <span className="arr">→</span></a>
              <a className="textlink" href="#work">View work →</a>
            </div>
          </div>
        </section>

        {/* SERVICES */}
        <section className="blk" id="services">
          <div className="wrap">
            <div className="sec-head center rv">
              <div className="kicker">01 — Services</div>
              <h2 className="sec-title">Three things, done <span className="grad">properly</span>.</h2>
              <p className="sec-lede">Contact us for more custom solutions.</p>
            </div>
            <div className="cards rv">
              {SERVICES.map((s) => (
                <div className="card" key={s.n}>
                  <span className="snum">{s.n}</span>
                  <div className="ic"><s.Icon /></div>
                  <h3>{s.title}</h3>
                  <p>{s.body}</p>
                  <ul>{s.bullets.map((b) => (<li key={b}><Check />{b}</li>))}</ul>
                  <div className="price"><span>Starting from</span>From {s.price}</div>
                </div>
              ))}
            </div>
          </div>
        </section>

        {/* WORK */}
        <section className="blk flush-top" id="work">
          <div className="wrap">
            <div className="sec-head center rv">
              <div className="kicker">02 — Selected work</div>
              <h2 className="sec-title">A few <span className="grad">recent</span> builds.</h2>
            </div>
            <div className="work-grid rv">
              {PROJECTS.map((p) => (
                <a className="proj" href={p.url} target="_blank" rel="noopener noreferrer" key={p.host}>
                  <div className="thumb">
                    <div className="bbar"><span className="d live" /><span className="d" /><span className="d" /><span className="u">{p.host}</span></div>
                    {/* eslint-disable-next-line @next/next/no-img-element */}
                    <img className="shot" src={p.shot} alt={`Screenshot of ${p.title}`} loading="lazy" />
                  </div>
                  <div className="proj-body">
                    <div className="top"><h3>{p.title}</h3><span className="visit">Visit ↗</span></div>
                    <div className="type">{p.type}</div>
                    <div className="desc">{p.desc}</div>
                  </div>
                </a>
              ))}
            </div>
          </div>
        </section>

        {/* PROCESS */}
        <section className="blk flush-top" id="process">
          <div className="wrap">
            <div className="sec-head center rv">
              <div className="kicker">03 — How it works</div>
              <h2 className="sec-title">A simple, three-step <span className="grad">process</span>.</h2>
            </div>
            <div className="cards rv">
              {PROCESS.map((p) => (
                <div className="card" key={p.title}>
                  <div className="ic"><p.Icon /></div>
                  <h3>{p.title}</h3>
                  <p>{p.body}</p>
                </div>
              ))}
            </div>
          </div>
        </section>

        {/* ABOUT */}
        <section className="blk flush-top" id="about">
          <div className="wrap">
            <div className="meet">
              <div className="meet-photo rv">
                <span className="tag">// Founder</span>
                {/* eslint-disable-next-line @next/next/no-img-element */}
                <img src={PORTRAIT} alt="Illustrated geometric portrait of the founder of yoco.works" />
              </div>
              <div className="meet-txt rv">
                <div className="kicker">04 — About</div>
                <h2>A small, focused <span className="grad">studio</span>.</h2>
                <p>yoco.works is a small studio building well-made websites and the workflows behind them.</p>
                <p>We keep the roster small on purpose — fewer clients, more care, and work built to last. Clear scope, flat fees, no surprises.</p>
                <div className="meet-stats">
                  <div className="ms"><div className="n">20+</div><div className="l">Years in tech</div></div>
                  <div className="ms"><div className="n">Flat</div><div className="l">Fee pricing</div></div>
                  <div className="ms"><div className="n">30d</div><div className="l">Free tweaks</div></div>
                </div>
              </div>
            </div>
          </div>
        </section>

        {/* TESTIMONIAL */}
        <section className="blk flush-top">
          <div className="wrap">
            <div className="quote-card rv">
              <div className="stars">★★★★★</div>
              <blockquote>&ldquo;Yehuda didn&rsquo;t just build a site; he automated my entire booking process. I saved 10 hours a week immediately.&rdquo;</blockquote>
              <div className="qby">— <b>Client name</b> · Founder, Studio</div>
              <div className="qnote">Placeholder — your real client quote goes here</div>
            </div>
          </div>
        </section>

        {/* FAQ */}
        <section className="blk flush-top" id="faq">
          <div className="wrap">
            <div className="sec-head center rv">
              <div className="kicker">05 — Reasonable questions</div>
              <h2 className="sec-title">Things people <span className="grad">actually</span> ask.</h2>
            </div>
            <div className="faq-list rv">
              {FAQS.map((f, i) => (
                <div className={`faq-item${openFaq === i ? " open" : ""}`} key={i} onClick={() => setOpenFaq(openFaq === i ? null : i)}>
                  <div className="faq-q"><span>{f.q}</span><span className="faq-toggle">+</span></div>
                  <div className="faq-a">{f.a}</div>
                </div>
              ))}
            </div>
          </div>
        </section>

        {/* CONTACT */}
        <section className="blk flush-top" id="contact">
          <div className="wrap">
            <div className="contact rv">
              <div className="contact-side">
                <div className="kicker">06 — Start a project</div>
                <h2>Tell us about your project.</h2>
                <p>Send a few details and we&rsquo;ll get back to you within a day — usually sooner.</p>
                <div className="meta">
                  <a href="mailto:hello@yoco.works">→ hello@yoco.works</a>
                  <span>EN · HE · ES · Remote</span>
                </div>
              </div>
              {sent ? (
                <div className="form-success">Thanks — your note is on its way. We&rsquo;ll reply <em>within a day</em>, usually sooner.<div className="sig">— yoco.works</div></div>
              ) : (
                <form className="form" onSubmit={handleSubmit}>
                  <div className="form-row">
                    <div className="field"><label>Your name</label><input type="text" name="name" required placeholder="Maya Chen" /></div>
                    <div className="field"><label>Email</label><input type="email" name="email" required placeholder="maya@studio.com" /></div>
                  </div>
                  <div className="form-row">
                    <div className="field"><label>Business or project</label><input type="text" name="business" placeholder="Studio Maya — bookkeeping" /></div>
                    <div className="field"><label>Timeline</label>
                      <select name="timeline" defaultValue="Soon as possible"><option>Soon as possible</option><option>Within a month</option><option>Within 2–3 months</option><option>Just exploring</option></select>
                    </div>
                  </div>
                  <div className="field full"><label>What can we help with?</label>
                    <div className="field-tags">
                      {HELP_OPTS.map((o) => (
                        <button type="button" key={o} className={`tag${help.includes(o) ? " active" : ""}`} onClick={() => toggleHelp(o)}>{o}</button>
                      ))}
                    </div>
                  </div>
                  <div className="field full"><label>Rough budget</label>
                    <div className="field-tags">
                      {BUDGET_OPTS.map((o) => (
                        <button type="button" key={o} className={`tag${budget === o ? " active" : ""}`} onClick={() => setBudget(o)}>{o}</button>
                      ))}
                    </div>
                  </div>
                  <div className="field full"><label>Tell us a little more</label><textarea name="message" required placeholder="What are you trying to build or fix? Even a sentence is fine." /></div>
                  <div className="form-submit">
                    <div className="privacy">Goes straight to our inbox. No list, no spam.</div>
                    <button type="submit" className="btn btn-primary">Send the note <span className="arr">→</span></button>
                  </div>
                </form>
              )}
            </div>
          </div>
        </section>

        {/* BIG CTA */}
        <section className="cta">
          <div className="wrap">
            <div className="cta-inner rv">
              <h2>Ready to simplify your business?</h2>
              <p>Tell us about your project and we&rsquo;ll take it from there.</p>
              <div className="hero-cta">
                <a className="btn btn-primary" href="#contact">Start a project <span className="arr">→</span></a>
                <a className="btn btn-ghost" href="#work">View work</a>
              </div>
            </div>
          </div>
        </section>
      </main>

      <footer>
        <div className="wrap">
          <div className="foot-top">
            <div className="foot-intro">
              <a className="brand" href="#top"><span className="yoco">yoco</span>{/* eslint-disable-next-line @next/next/no-img-element */}<img className="cap" src={CAP} alt="" /><span className="works">works</span></a>
              <p>Well-made websites and the quiet workflows behind them.</p>
            </div>
            <div className="foot-links">
              <div className="foot-col"><h5>Studio</h5><a href="#services">Services</a><a href="#work">Work</a><a href="#process">Process</a><a href="#about">About</a><a href="#faq">FAQ</a></div>
              <div className="foot-col"><h5>Start</h5><a href="#contact">Start a project</a><a href="mailto:hello@yoco.works">hello@yoco.works</a></div>
              <div className="foot-col"><h5>Elsewhere</h5><a href="#">Twitter / X</a><a href="#">LinkedIn</a></div>
            </div>
          </div>
          <div className="foot-fine">
            <span>© 2026 · yoco.works</span>
            <span>Built with care</span>
          </div>
        </div>
      </footer>
    </>
  );
}
